package lacoderepeticao;

public class For6 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		//6. Escreva um sistema que calcule e imprima a tabuada do 8 (1 a 10).
		
		for (int i=1;i<=10;i++) {
			int mult=i*8;
			System.out.println(mult);
		}
	}

}
